const LOCAL_API  = "http://localhost:5000";
const HOSTED_API = "https://your-app.onrender.com"; // update when deployed

// Tries local first, falls back to hosted
const BASE = process.env.REACT_APP_API_URL || LOCAL_API;

export async function predictImage(file) {
  const form = new FormData();
  form.append("file", file);
  const res = await fetch(`${BASE}/predict`, { method: "POST", body: form });
  if (!res.ok) throw new Error(`Prediction failed: ${res.status}`);
  return res.json();
}

export async function fetchStats() {
  const res = await fetch(`${BASE}/stats`);
  if (!res.ok) throw new Error(`Stats fetch failed: ${res.status}`);
  return res.json();
}

export async function generateReport(predictionResult, imageFile) {
  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "x-api-key": process.env.REACT_APP_ANTHROPIC_API_KEY,
      "anthropic-version": "2023-06-01",
      "anthropic-dangerous-direct-browser-access": "true"
    },
    body: JSON.stringify({
      model: "claude-sonnet-4-20250514",
      max_tokens: 1000,
      messages: [{
        role: "user",
        content: `You are an urban cleanliness analyst. A CNN model has analysed a street image and produced the following result:

- Classification: ${predictionResult.label}
- Confidence: ${(predictionResult.confidence * 100).toFixed(1)}%
- Uncertainty (MC Dropout std): ${predictionResult.uncertainty}
- Predictive entropy: ${predictionResult.entropy}
- Flagged as ambiguous: ${predictionResult.is_ambiguous}

Write a professional 4-sentence cleanliness report for a municipal authority. Cover: (1) the classification verdict and confidence, (2) what this implies about the street's condition, (3) a recommended action (cleaning priority, routine monitoring, or no action), (4) a note on reliability based on the uncertainty value. Be concise and professional. Do not use bullet points.`
      }]
    })
  });
  if (!res.ok) throw new Error(`LLM report failed: ${res.status}`);
  const data = await res.json();
  return data.content[0].text;
}
